56: func NewResourceExpirationEvaluator(currentVersion *apimachineryversion.Version) (ResourceExpirationEvaluator, error) {
57: 	if currentVersion == nil {
58: 		return nil, fmt.Errorf("empty NewResourceExpirationEvaluator currentVersion")
59: 	}
60: 	klog.V(1).Infof("NewResourceExpirationEvaluator with currentVersion: %s.", currentVersion)
61: 	ret := &resourceExpirationEvaluator{
62: 		strictRemovedHandlingInAlpha: false,
63: 	}
64: 	// Only keeps the major and minor versions from input version.
65: 	ret.currentVersion = apimachineryversion.MajorMinor(currentVersion.Major(), currentVersion.Minor())
66: 	ret.isAlpha = strings.Contains(currentVersion.PreRelease(), "alpha")
67: 
68: 	if envString, ok := os.LookupEnv("KUBE_APISERVER_STRICT_REMOVED_API_HANDLING_IN_ALPHA"); !ok {
69: 		// do nothing
70: 	} else if envBool, err := strconv.ParseBool(envString); err != nil {
71: 		return nil, err
72: 	} else {
73: 		ret.strictRemovedHandlingInAlpha = envBool
74: 	}
75: 
76: 	if envString, ok := os.LookupEnv("KUBE_APISERVER_SERVE_REMOVED_APIS_FOR_ONE_RELEASE"); !ok {
77: 		// do nothing
78: 	} else if envBool, err := strconv.ParseBool(envString); err != nil {
79: 		return nil, err
80: 	} else {
81: 		ret.serveRemovedAPIsOneMoreRelease = envBool
82: 	}
83: 
84: 	return ret, nil
85: }
