119: func (e *resourceExpirationEvaluator) ShouldServeForVersion(majorRemoved, minorRemoved int) bool {
120: 	removedVer := apimachineryversion.MajorMinor(uint(majorRemoved), uint(minorRemoved))
121: 	if removedVer.GreaterThan(e.currentVersion) {
122: 		return true
123: 	}
124: 	if removedVer.LessThan(e.currentVersion) {
125: 		return false
126: 	}
127: 	// at this point major and minor are equal, so this API should be removed when the current release GAs.
128: 	// If this is an alpha tag, don't remove by default, but allow the option.
129: 	// If the cluster-admin has requested serving one more release, allow it.
130: 	if e.isAlpha && e.strictRemovedHandlingInAlpha { // don't serve in alpha if we want strict handling
131: 		return false
132: 	}
133: 	if e.isAlpha { // alphas are allowed to continue serving expired betas while we clean up the test
134: 		return true
135: 	}
136: 	if e.serveRemovedAPIsOneMoreRelease { // cluster-admins are allowed to kick the can one release down the road
137: 		return true
138: 	}
139: 	return false
140: }
