570: // MonitorRequest handles standard transformations for client and the reported verb and then invokes Monitor to record
571: // a request. verb must be uppercase to be backwards compatible with existing monitoring tooling.
572: func MonitorRequest(req *http.Request, verb, group, version, resource, subresource, scope, component string, deprecated bool, removedRelease string, httpCode, respSize int, elapsed time.Duration) {
573: 	requestInfo, ok := request.RequestInfoFrom(req.Context())
574: 	if !ok || requestInfo == nil {
575: 		requestInfo = &request.RequestInfo{Verb: req.Method, Path: req.URL.Path}
576: 	}
577: 	// We don't use verb from <requestInfo>, as this may be propagated from
578: 	// InstrumentRouteFunc which is registered in installer.go with predefined
579: 	// list of verbs (different than those translated to RequestInfo).
580: 	// However, we need to tweak it e.g. to differentiate GET from LIST.
581: 	reportedVerb := cleanVerb(CanonicalVerb(strings.ToUpper(req.Method), scope), verb, req, requestInfo)
582: 
583: 	dryRun := cleanDryRun(req.URL)
584: 	elapsedSeconds := elapsed.Seconds()
585: 	requestCounter.WithContext(req.Context()).WithLabelValues(reportedVerb, dryRun, group, version, resource, subresource, scope, component, codeToString(httpCode)).Inc()
586: 	// MonitorRequest happens after authentication, so we can trust the username given by the request
587: 	info, ok := request.UserFrom(req.Context())
588: 	if ok && info.GetName() == user.APIServerUser {
589: 		apiSelfRequestCounter.WithContext(req.Context()).WithLabelValues(reportedVerb, resource, subresource).Inc()
590: 	}
591: 	if deprecated {
592: 		deprecatedRequestGauge.WithContext(req.Context()).WithLabelValues(group, version, resource, subresource, removedRelease).Set(1)
593: 		audit.AddAuditAnnotation(req.Context(), deprecatedAnnotationKey, "true")
594: 		if len(removedRelease) > 0 {
595: 			audit.AddAuditAnnotation(req.Context(), removedReleaseAnnotationKey, removedRelease)
596: 		}
597: 	}
